import cron from 'node-cron';
import { Task, NotificationLog } from './models';
import { notifyAssignee } from './notificationService';
import { getDbCollection } from './db';

/**
 * Schedule tasks using node-cron and manage task rotations
 */
export class SchedulingEngine {
  /**
   * Initializes the scheduling engine by loading all tasks and setting up cron jobs
   */
  public static async initialize() {
    const tasks: Task[] = await getDbCollection<Task>('Tasks').find({ status: 'active' }).toArray();
    tasks.forEach(task => this.scheduleTask(task));
    await this.catchUpNotifications();
  }

  /**
   * Schedules a task based on its recurrence settings
   * @param task The task to schedule
   */
  public static scheduleTask(task: Task) {
    const scheduleString = this.getCronSchedule(task);
    cron.schedule(scheduleString, async () => {
      await this.handleTask(task);
    });
  }

  /**
   * Generates a cron schedule string from the task's recurrence details
   * @param task The task from which to generate the schedule
   * @returns A cron formatted string
   */
  private static getCronSchedule(task: Task): string {
    if (task.recurrence.type === 'daily') {
      return `0 ${this.extractCronTime(task.recurrence.time)} * * *`;
    } else if (task.recurrence.type === 'weekly') {
      const days = task.recurrence.daysOfWeek?.join(',') || '*';
      return `0 ${this.extractCronTime(task.recurrence.time)} * * ${days}`;
    } else {
      // Custom logic if needed
      return '';
    }
  }

  /**
   * Handle the task's notification
   * @param task The task to notify
   */
  private static async handleTask(task: Task) {
    const assignee = this.getCurrentAssignee(task);
    const status = await notifyAssignee(assignee, task);
    await this.logNotification(task.id, status);
    this.rotateAssignee(task);
  }

  /**
   * Determines the current assignee to notify, taking into account unavailability
   * @param task The task to determine for
   * @returns The ID of the current assignee
   */
  private static getCurrentAssignee(task: Task) {
    const availableAssignees = task.assignees.filter(assignee =>
      !(task.unavailableMembers?.includes(assignee))
    );
    return availableAssignees[task.rotationIndex % availableAssignees.length];
  }

  /**
   * Rotates the assignee index for the next notification
   * @param task The task to rotate
   */
  private static rotateAssignee(task: Task) {
    const nextIndex = (task.rotationIndex + 1) % task.assignees.length;
    getDbCollection<Task>('Tasks').updateOne(
      { id: task.id },
      { $set: { rotationIndex: nextIndex } }
    );
  }

  /**
   * Log a notification attempt
   * @param taskId Id of the task
   * @param status The status of the notification attempt
   */
  private static async logNotification(taskId: import('mongodb').ObjectId, status: 'success' | 'failed') {
    const log: NotificationLog = {
      id: new import('mongodb').ObjectId(),
      taskId,
      sentAt: new Date(),
      status,
      retryCount: 0
    };
    await getDbCollection<NotificationLog>('NotificationLogs').insertOne(log);
  }

  /**
   * Retrieves the hour and minute from the time string for cron scheduling
   * @param time - The time formatted as "HH:mm"
   * @returns A string to be used in a cron schedule
   */
  private static extractCronTime(time: string): string {
    return time.split(':').reverse().join(' ');
  }

  /**
   * Executes catch-up logic to resend missed notifications
   */
  private static async catchUpNotifications() {
    const now = new Date();
    const tasks: Task[] = await getDbCollection<Task>('Tasks').find({ status: 'active' }).toArray();
    await Promise.all(tasks.map(async (task) => {
      let nextRun = this.calculateNextRun(task);
      if (nextRun < now) {
        await this.handleTask(task);
      }
    }));
  }

  /**
   * Calculate the next scheduled run time for a task
   * @param task The task to calculate the run time for
   * @returns The Date of the next run
   */
  private static calculateNextRun(task: Task): Date {
    // For demonstration, this assumes daily recurrence; you would expand this for other types
    let nextRun = new Date();
    const [hour, minute] = task.recurrence.time.split(':');
    nextRun.setHours(parseInt(hour), parseInt(minute), 0, 0);
    if (nextRun < new Date()) {
      nextRun.setDate(nextRun.getDate() + 1);
    }
    return nextRun;
  }
}
